{
  "kind": "vv_requirements_discovery",
  "vvRequirements": [
    {
      "id": "VV-REDIRECT-LATENCY",
      "category": "performance",
      "target": "P95 latency for the redirect endpoint must respond quickly",
      "measurement": "Server-side latency for the redirect endpoint under nominal load",
      "threshold": "≤ 100 ms over any rolling 5-minute window",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "NFR-1 — Redirect latency",
        "excerpt": "AC-NFR1: P95 latency for the redirect endpoint, measured server-side, is ≤ 100 ms over any rolling 5-minute window under nominal load."
      }
    },
    {
      "id": "VV-AVAILABILITY-UPTIME",
      "category": "availability",
      "target": "Monthly uptime for the redirect endpoint",
      "measurement": "Measured against the redirect endpoint, including planned maintenance windows",
      "threshold": "≥ 99.9%",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "NFR-3 — Service availability",
        "excerpt": "AC-NFR3.1: Monthly uptime ≥ 99.9% measured against the redirect endpoint, including planned maintenance windows."
      }
    },
    {
      "id": "VV-AVAILABILITY-RTO",
      "category": "availability",
      "target": "Recovery Time Objective on full regional failure",
      "measurement": "Time elapsed between regional failure and recovery of service",
      "threshold": "≤ 15 minutes",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "NFR-3 — Service availability",
        "excerpt": "AC-NFR3.2: Recovery Time Objective (RTO) on full regional failure ≤ 15 minutes."
      }
    },
    {
      "id": "VV-SECURITY-ENCRYPTION",
      "category": "security",
      "target": "Original URLs stored encrypted at rest",
      "measurement": "Direct read of the underlying Postgres data files",
      "threshold": "Yields no plaintext occurrence of any submitted URL",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "NFR-2 — Stored URLs encrypted at rest",
        "excerpt": "AC-NFR2: A direct read of the underlying Postgres data files yields no plaintext occurrence of any submitted URL."
      }
    },
    {
      "id": "VV-OBSERVABILITY-LOGGING",
      "category": "observability",
      "target": "Structured JSON logs to stdout ingested by the platform",
      "measurement": "Validation of log format and destination",
      "threshold": "All logs conform to structured JSON and stream to stdout",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "Technical Constraints",
        "excerpt": "Observability: structured JSON logs to stdout; logs ingested by the platform's standard log aggregator."
      }
    },
    {
      "id": "VV-SECURITY-TRANSPORT",
      "category": "security",
      "target": "HTTPS enforced on all public endpoints",
      "measurement": "Response to HTTP requests",
      "threshold": "HTTP requests must redirect to HTTPS",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "Technical Constraints",
        "excerpt": "Transport: HTTPS only on all public endpoints; HTTP requests redirect to HTTPS."
      }
    },
    {
      "id": "VV-DATA-INTEGRITY",
      "category": "reliability",
      "target": "Every stored slug in the mappings table must be unique",
      "measurement": "Database query on url_mappings table",
      "threshold": "SELECT slug, COUNT(*) FROM url_mappings GROUP BY slug HAVING COUNT(*) > 1 returns zero rows",
      "source_ref": {
        "document_path": "tinyurl-thin-slice.md",
        "section_heading": "FR-2 — Slug uniqueness invariant",
        "excerpt": "AC-2.1: A database query SELECT slug, COUNT(*) FROM url_mappings GROUP BY slug HAVING COUNT(*) > 1 returns zero rows."
      }
    }
  ]
}
